    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = tasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t =>
                t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return filtered.ToList();
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = tasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                tasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask(
        (string Title, string Assignee, string Priority, DateTime DueDate) data,
        string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            // The service creates with a default status; ensure it matches the column
            tasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

