@using sv_d6feb16b5ddc41c7a436cbd7d6c46c0e.Services

<div class="board-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-cards">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>

    @if (showForm)
    {
        <AddTaskForm OnSave="HandleSave" OnCancel="HandleCancel" />
    }
    else
    {
        <button class="btn-add-task" @onclick="() => showForm = true">+ Add Task</button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveRight { get; set; }

    [Parameter]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    /// <summary>The default status to assign when creating tasks in this column.</summary>
    [Parameter]
    public string DefaultStatus { get; set; } = "To Do";

    private bool showForm;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) formData)
    {
        await OnTaskCreated.InvokeAsync(formData);
        showForm = false;
    }

    private void HandleCancel()
    {
        showForm = false;
    }
}

