@page "/board"
@rendermode InteractiveServer
@using sv_d6feb16b5ddc41c7a436cbd7d6c46c0e.Components.Board
@using sv_d6feb16b5ddc41c7a436cbd7d6c46c0e.Services
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (isLoading)
{
    <p class="loading-message">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <div class="error-message">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="tasks" />

    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="board-columns">
        <BoardColumn ColumnName="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnMoveRight="task => MoveTask(task, "In Progress")"
                     OnTaskCreated="data => CreateTask(data, "To Do")"
                     DefaultStatus="To Do" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnMoveLeft="task => MoveTask(task, "To Do")"
                     OnMoveRight="task => MoveTask(task, "Done")"
                     OnTaskCreated="data => CreateTask(data, "In Progress")"
                     DefaultStatus="In Progress" />

        <BoardColumn ColumnName="Done"
                     Tasks="GetFilteredTasks("Done")"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnMoveLeft="task => MoveTask(task, "In Progress")"
                     OnTaskCreated="data => CreateTask(data, "Done")"
                     DefaultStatus="Done" />
    </div>
}

@code {
    private List<TaskItem> tasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = tasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t =>
                t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return filtered.ToList();
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = tasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                tasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask(
        (string Title, string Assignee, string Priority, DateTime DueDate) data,
        string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            // The service creates with a default status; ensure it matches the column
            tasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

